package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.dmfappl;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.CategorieKengetalFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.WerkbonusKomtInAanmerking;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentagesFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RkmCoreHrConfiguratieManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetal;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import be.schaubroeck.lpb.tools.service.RegimeRszppoService;
import com.google.common.collect.Sets;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Set;

@AllArgsConstructor
public class WerkbonusKomtInAanmerkingDmfappl implements WerkbonusKomtInAanmerking {

    private static final Set<Hoedanigheid> KOMT_IN_AAN_MERKING_DMFAPPL =
            Sets.immutableEnumSet(Hoedanigheid.WACHTWEDDEN, Hoedanigheid.VASTBENOEMDEN, Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN,
                    Hoedanigheid.GESUBSIDIEERDE_CONTRACTUELEN, Hoedanigheid.STUDENTEN, Hoedanigheid.MONITOREN, Hoedanigheid.TOEZICHT_BEGELEIDING_BIJLES,
                    Hoedanigheid.ANDERE, Hoedanigheid.ERKENTELIJKHEIDSPREMIE, Hoedanigheid.VRIJWILLIGE_BRANDWEER_ERKENTELIJKHEIDSPREMIE,
                    Hoedanigheid.MANDATARISSEN_NIET_BESCHERMD, Hoedanigheid.VRIJWILLIGE_BRANDWEER, Hoedanigheid.ONTHAALOUDERS);

    protected final BijdragePercentagesFactory bijdragePercentagesFactory;
    protected final RegimeRszppoService regimeRszppoService;
    protected final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;

    @Override
    public boolean checkOpdracht(Opdracht opdracht, RekenTijd rekenTijd) {
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        return KOMT_IN_AAN_MERKING_DMFAPPL.contains(hoedanigheid) || (hoedanigheid == Hoedanigheid.VRIJWILLIGERS
                && RekenTools.getTijdperk(rekenTijd) == AkeTijdperk.RSZPPO);
    }

    @Override
    public boolean checkSleutelGegevens(
            SleutelGegevens aggregaat, RekenTijd rekenTijd, RegulManager regulManager, RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager) {
        boolean inAanmerkingVoorWerkbonus = true;
        if (RekenTools.getTijdperk(rekenTijd) == AkeTijdperk.DMFAPPL) {
            WerkgeversCategorie werkgeversCategorie = aggregaat.getWerkgeversCategorie();
            DmfapplWnkengetal werknemersKengetal = aggregaat.getWerknemersKengetal();
            CategorieKengetal categorieKengetal = CategorieKengetalFactory.getCategorieKengetal(rekenTijd, werkgeversCategorie, werknemersKengetal);
            inAanmerkingVoorWerkbonus = !categorieKengetal.isStudentMetBijzondereCategorie();
        }
        if (inAanmerkingVoorWerkbonus && !getRekenWerkbonusPerUurBetaalden(rkmCoreHrConfiguratieManager, aggregaat.getOpdracht(), rekenTijd)) {
            inAanmerkingVoorWerkbonus = !aggregaat.isOnregelmatigPerPrestatieOfPerUur();
        }
        if (inAanmerkingVoorWerkbonus) {
            BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
            BigDecimal percentageBijdrageRsz = bijdragePercentages.getInhoudingRsz(aggregaat);
            inAanmerkingVoorWerkbonus = percentageBijdrageRsz.compareTo(new BigDecimal("0.1307")) == 0;
        }
        return inAanmerkingVoorWerkbonus;
    }

    private boolean getRekenWerkbonusPerUurBetaalden(RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager, Opdracht opdracht, RekenTijd rekenTijd) {
        RkmCoreHrConfiguratie rkmCoreHrConfiguratie = rkmCoreHrConfiguratieManager.getRkmCoreHrConfiguratie(opdracht, rekenTijd);
        return rkmCoreHrConfiguratie != null && rkmCoreHrConfiguratie.isRekenWerkbonusPerUurBetaalden();
    }

    @Override
    public boolean checkLoonElement(SleutelGegevens aggregaat, LoonElement element, RekenTijd rekenTijd) {
        AardKodeExtensie loonCode = element.getAardKodeExtensie();
        boolean inAanmerkingVoorWerkbonus = !loonCode.behoortTotGroep(LooncodeGroepKeyStrings.GEEN_WERKBONUS_LAGE_LONEN_KEY);
        if (inAanmerkingVoorWerkbonus) {
            LocalDate datum = TimeTools.getZoekDatum(aggregaat, rekenTijd.rekenPeriode);
            inAanmerkingVoorWerkbonus = BerekenWerkbonusDmfapplHelperFactory.isInAanmerkingVoorWerkbonusDmfappl(dmfapplBasisBijdrageService, rekenTijd,
                    aggregaat.getWerkgeversCategorie(),
                    aggregaat.getWerknemersKengetal(), loonCode, datum);
        }
        return inAanmerkingVoorWerkbonus;
    }
}
